export const 鎮宅腹脹 = (bi) => {
    const u = bi.u, k = 2.7;
    const X = (c) => (c - 3.95) * k;
    const Z = (r) => (r - 0.7) * k + 2;
    const 線 = (書, 寬 = 0.38) => bi.一筆({ 寬: 寬 * u, 起: '藏', 收: '回' }, 書);
    const 出 = (書, 寬 = 0.4) => bi.一筆({ 寬: 寬 * u, 起: '藏', 收: '出' }, 書);
    const 圈 = (x, z, r = 0.28) => {
        const c = bi.ctx;
        c.save();
        c.lineWidth = 0.3 * u;
        bi.A(X(x), Z(z), r * k);
        c.restore();
    };
    // 符頭：桿二
    線(p => p.M(X(1.0), Z(1.3)).L(X(5.5), Z(1.2)));
    圈(0.7, 1.3);
    圈(5.8, 1.2);
    線(p => p.M(X(1.0), Z(2.5)).L(X(5.5), Z(2.4)));
    圈(0.7, 2.5);
    圈(5.8, 2.4);
    // 右緣圈列三
    圈(6.4, 3.5);
    圈(6.5, 4.3);
    圈(6.6, 5.1);
    圈(6.9, 6.6);
    // 左厂王形（摹形）
    線(p => p.M(X(0.8), Z(3.8)).L(X(3.0), Z(3.7)), 0.38);
    出(p => p.M(X(1.0), Z(3.8)).C(X(0.9), Z(4.6), X(0.8), Z(5.4), X(0.7), Z(6.1)), 0.38);
    線(p => p.M(X(1.3), Z(4.5)).L(X(2.9), Z(4.45)), 0.3);
    出(p => p.M(X(2.1), Z(4.5)).C(X(2.1), Z(5.2), X(2.0), Z(5.7), X(1.5), Z(5.9)), 0.32);
    // 乙曲
    線(p => p.M(X(3.5), Z(3.8))
        .C(X(4.3), Z(3.9), X(4.3), Z(4.4), X(3.7), Z(4.7))
        .C(X(3.2), Z(5.0), X(3.4), Z(5.6), X(4.3), Z(5.7)), 0.36);
    // 亖桁帶三
    線(p => p.M(X(0.7), Z(6.7)).L(X(6.6), Z(6.6)), 0.42);
    線(p => p.M(X(0.7), Z(7.5)).L(X(6.6), Z(7.4)), 0.42);
    線(p => p.M(X(0.7), Z(8.3)).L(X(6.6), Z(8.2)), 0.42);
    // 左目箱三疊
    const 目 = (x0, x1, z0, z1) => {
        線(p => p.M(X(x0), Z(z0)).L(X(x0), Z(z1)).L(X(x1), Z(z1 - 0.05))
            .L(X(x1), Z(z0 - 0.05)).L(X(x0 - 0.05), Z(z0)));
        線(p => p.M(X(x0 + 0.1), Z((z0 + z1) / 2)).L(X(x1 - 0.1), Z((z0 + z1) / 2 - 0.03)), 0.32);
    };
    目(0.8, 3.3, 8.9, 11.2);
    目(0.8, 3.3, 11.7, 14.0);
    目(0.8, 3.3, 14.5, 16.6);
    // 乡三曲
    const 乡 = (cz) => 出(p => p.M(X(2.6), Z(cz))
        .C(X(1.6), Z(cz + 0.35), X(1.4), Z(cz + 0.7), X(2.2), Z(cz + 0.85)), 0.34);
    乡(16.9);
    乡(17.65);
    乡(18.35);
    // 右目箱（高，二桁三格）
    線(p => p.M(X(4.0), Z(8.9)).L(X(4.0), Z(12.6)).L(X(6.6), Z(12.55))
        .L(X(6.6), Z(8.85)).L(X(3.95), Z(8.9)));
    線(p => p.M(X(4.1), Z(10.1)).L(X(6.5), Z(10.07)), 0.32);
    線(p => p.M(X(4.1), Z(11.3)).L(X(6.5), Z(11.27)), 0.32);
    // 木形（摹形）
    線(p => p.M(X(4.3), Z(13.5)).L(X(6.4), Z(13.45)), 0.36);
    線(p => p.M(X(5.3), Z(12.95)).L(X(5.28), Z(15.5)), 0.38);
    出(p => p.M(X(5.3), Z(13.7)).C(X(5.0), Z(14.2), X(4.7), Z(14.6), X(4.3), Z(15.0)), 0.34);
    出(p => p.M(X(5.3), Z(13.7)).C(X(5.6), Z(14.2), X(5.9), Z(14.6), X(6.3), Z(15.0)), 0.34);
    // 夂曲尾（摹形從簡）
    出(p => p.M(X(5.5), Z(16.0)).C(X(5.2), Z(16.5), X(4.9), Z(16.9), X(4.5), Z(17.3)), 0.36);
    線(p => p.M(X(4.7), Z(16.4)).L(X(6.2), Z(16.75)), 0.34);
    出(p => p.M(X(6.2), Z(16.75))
        .C(X(5.7), Z(17.5), X(5.2), Z(18.2), X(4.8), Z(18.7))
        .C(X(4.7), Z(18.9), X(4.8), Z(19.05), X(5.1), Z(19.05)), 0.36);
};
